export function parseRow(row) {
  const quantity = Number(row.quantity);
  if (!quantity) throw new ValidationError("quantity required");
  return { id: row.id, quantity, source: row.source };
}

export function resolveImportPath(input) {
  return join(process.cwd(), input);
}
